const countriesJson = $input.first().json.countries_json;
const countries = JSON.parse(countriesJson);
return countries.map(c => ({ json: c }));

// Extraire le texte de la réponse Claude
const content = $input.first().json.content;
let textContent = '';

for (const block of content) {
  if (block.type === 'text') {
    textContent += block.text;
  }
}

// Extraire le JSON du texte
const jsonMatch = textContent.match(/\[[\s\S]*\]/);
if (!jsonMatch) {
  // Retourner un tableau vide si pas de JSON
  return [{ json: { articles: [], country_code: $('Loop Countries').first().json.code, country_name: $('Loop Countries').first().json.name, error: 'No JSON found in Claude response' } }];
}

try {
  const articles = JSON.parse(jsonMatch[0]);
  const countryCode = $('Loop Countries').first().json.code;
  const countryName = $('Loop Countries').first().json.name;

  return articles.map((article, index) => ({
    json: {
      country_code: countryCode,
      country_name: countryName,
      article_index: index,
      ...article
    }
  }));
} catch (e) {
  return [{ json: { articles: [], country_code: $('Loop Countries').first().json.code, country_name: $('Loop Countries').first().json.name, error: 'JSON parse error: ' + e.message } }];
}

const items = $input.all();
const results = [];

for (const item of items) {
  const ytData = item.json;
  let videoId = '';
  let videoTitle = '';
  let videoThumbnail = '';

  if (ytData.items && ytData.items.length > 0) {
    videoId = ytData.items[0].id?.videoId || '';
    videoTitle = ytData.items[0].snippet?.title || '';
    videoThumbnail = ytData.items[0].snippet?.thumbnails?.high?.url || '';
  }

  // Récupérer les données de l'article précédent
  const prevData = $('Loop Articles').first().json;

  results.push({
    json: {
      ...prevData,
      youtube_video_id: videoId,
      youtube_video_title: videoTitle,
      youtube_thumbnail: videoThumbnail,
      youtube_embed_url: videoId ? `https://www.youtube.com/embed/${videoId}` : ''
    }
  });
}

return results;

// Agrège tous les articles par pays
const allItems = $input.all();
const aggregated = {};

for (const item of allItems) {
  const code = item.json.country_code;
  if (!code) continue;
  if (!aggregated[code]) {
    aggregated[code] = [];
  }
  aggregated[code].push(item.json);
}

return [{
  json: {
    news_data: aggregated,
    updated_at: new Date().toISOString(),
    countries_count: Object.keys(aggregated).length,
    total_articles: Object.values(aggregated).reduce((sum, arr) => sum + arr.length, 0)
  }
}];

const data = $input.first().json;
return [{
  json: {
    status: 'success',
    message: `G20 Pulse mis à jour: ${data.countries_count || 20} pays, ${data.total_articles || 100} articles`,
    timestamp: new Date().toISOString()
  }
}];
